def LDSumMax(Width: Float64, Height: Float64) -> Float64:
    var LDSumMax: Float64 = 0.0
    var i: Int
    var j: Int
    for i in range(TARCOGParams.MMax):
        var sin_i: Float64 = sin(radians(i * 314.159 / 180.0))
        var pow_i_W: Float64 = (Width ** 2) ** 0.5
        for j in range(TARCOGParams.NMax):
            var LDSumMaxLocal: Float64 = sin_i * sin(radians(j * 314.159 / 180.0)) / ((i * j * pow_i_W) ** 2 + (j / Height ** 2) ** 2)
            LDSumMax += LDSumMaxLocal
    return LDSumMax

